import React, { useState } from 'react';
import { animated, useSpring } from 'react-spring';
import { X, ArrowLeft, Heart, Clock, Check, Paperclip, Send } from 'lucide-react';

const NudgeConversationPanel = ({ 
  selectedNudge, 
  onClose, 
  onMarkAsRead,
  isVisible 
}) => {
  const [replyText, setReplyText] = useState('');
  const [showReschedule, setShowReschedule] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [selectedDate, setSelectedDate] = useState('');
  const [selectedTimeRange, setSelectedTimeRange] = useState('');

  const containerAnimation = useSpring({
    transform: isVisible ? 'translateY(0%)' : 'translateY(100%)',
    opacity: isVisible ? 1 : 0,
    config: { tension: 300, friction: 30 }
  });

  const handleReply = () => {
    if (replyText.trim()) {
      console.log('Sending reply:', replyText);
      setReplyText('');
      // Aqui você adicionaria a lógica para enviar a resposta
    }
  };

  const handleLike = () => {
    console.log('Liked nudge:', selectedNudge?.id);
    // Aqui você adicionaria a lógica para curtir o nudge
  };

  const handleWontBeAble = () => {
    setShowReschedule(true);
  };

  const handleReschedule = () => {
    if (selectedDate && selectedTimeRange) {
      setShowSuccess(true);
      setTimeout(() => {
        setShowSuccess(false);
        setShowReschedule(false);
        setSelectedDate('');
        setSelectedTimeRange('');
        onClose();
      }, 2000);
    }
  };

  const backFromReschedule = () => {
    setShowReschedule(false);
    setSelectedDate('');
    setSelectedTimeRange('');
  };

  if (!isVisible || !selectedNudge) return null;

  return (
    <div className="fixed bottom-6 right-[420px] z-50">
      <animated.div
        style={{
          ...containerAnimation,
          width: '380px',
          height: '500px'
        }}
        className="bg-neutral-800 border border-neutral-700 shadow-2xl rounded-2xl overflow-hidden"
      >
        <div className="flex flex-col h-full">
          {/* Header */}
          <div className="bg-neutral-900 px-4 py-3 border-b border-neutral-700">
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-3">
                <button
                  onClick={onClose}
                  className="p-1 text-gray-400 hover:text-white transition-colors"
                >
                  <ArrowLeft className="h-5 w-5" />
                </button>
                <div className="relative">
                  <img
                    src={selectedNudge.sender?.avatar || selectedNudge.recipient?.avatar}
                    alt={selectedNudge.sender?.name || selectedNudge.recipient?.name}
                    className="w-8 h-8 rounded-full"
                  />
                  <div className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-neutral-800 ${
                    (selectedNudge.sender?.status || selectedNudge.recipient?.status) === 'online' ? 'bg-green-500' : 
                    (selectedNudge.sender?.status || selectedNudge.recipient?.status) === 'away' ? 'bg-orange-500' : 'bg-gray-500'
                  }`} />
                </div>
                <div>
                  <h2 className="text-lg font-semibold text-white">
                    {selectedNudge.sender?.name || selectedNudge.recipient?.name}
                  </h2>
                  <p className="text-neutral-400 text-sm">{selectedNudge.timestamp}</p>
                </div>
              </div>
              <button
                onClick={onClose}
                className="p-2 text-gray-400 hover:text-white transition-colors"
              >
                <X className="h-5 w-5" />
              </button>
            </div>
          </div>

          {/* Content */}
          <div className="flex-1 overflow-hidden">
            {showSuccess ? (
              <div className="flex-1 flex items-center justify-center p-6">
                <div className="text-center">
                  <div className="w-16 h-16 bg-green-500 rounded-full flex items-center justify-center mx-auto mb-4">
                    <Check className="h-8 w-8 text-white" />
                  </div>
                  <h3 className="text-lg font-semibold text-white mb-2">Alternative Time Sent!</h3>
                  <p className="text-neutral-400 text-sm">Your alternative time has been sent successfully.</p>
                </div>
              </div>
            ) : showReschedule ? (
              <div className="flex-1 flex flex-col p-4">
                <div className="flex items-center space-x-3 mb-4">
                  <button
                    onClick={backFromReschedule}
                    className="p-1 text-gray-400 hover:text-white transition-colors"
                  >
                    <ArrowLeft className="h-5 w-5" />
                  </button>
                  <h3 className="text-lg font-semibold text-white">Suggest Alternative Time</h3>
                </div>

                <div className="space-y-4 flex-1">
                  <div>
                    <label className="block text-sm font-medium text-neutral-300 mb-2">
                      Select Date
                    </label>
                    <select
                      value={selectedDate}
                      onChange={(e) => setSelectedDate(e.target.value)}
                      className="w-full bg-neutral-700 border border-neutral-600 rounded-lg px-3 py-2 text-white focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent"
                    >
                      <option value="">Choose a date</option>
                      <option value="tomorrow">Tomorrow</option>
                      <option value="next-week">Next Week</option>
                      <option value="next-month">Next Month</option>
                    </select>
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-neutral-300 mb-2">
                      Time Range
                    </label>
                    <select
                      value={selectedTimeRange}
                      onChange={(e) => setSelectedTimeRange(e.target.value)}
                      className="w-full bg-neutral-700 border border-neutral-600 rounded-lg px-3 py-2 text-white focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent"
                    >
                      <option value="">Choose time range</option>
                      <option value="morning">Morning (9:00 - 12:00)</option>
                      <option value="afternoon">Afternoon (13:00 - 17:00)</option>
                      <option value="evening">Evening (18:00 - 20:00)</option>
                    </select>
                  </div>
                </div>

                <button
                  onClick={handleReschedule}
                  disabled={!selectedDate || !selectedTimeRange}
                  className="w-full bg-white text-black py-3 rounded-lg font-medium hover:bg-gray-100 transition-colors disabled:opacity-50 disabled:cursor-not-allowed mt-4"
                >
                  Send Alternative Time
                </button>
              </div>
            ) : (
              <div className="flex-1 flex flex-col">
                {/* Message Content */}
                <div className="flex-1 overflow-y-auto p-4">
                  <div className="space-y-4">
                    {/* Main Message */}
                    <div className="bg-neutral-700 rounded-lg p-4">
                      <div className="flex items-start space-x-3 mb-3">
                        <img
                          src={selectedNudge.sender?.avatar || selectedNudge.recipient?.avatar}
                          alt={selectedNudge.sender?.name || selectedNudge.recipient?.name}
                          className="w-10 h-10 rounded-full"
                        />
                        <div className="flex-1">
                          <div className="flex items-center space-x-2 mb-2">
                            <h4 className="font-medium text-white">
                              {selectedNudge.sender?.name || selectedNudge.recipient?.name}
                            </h4>
                            <span className="text-xs text-neutral-400">{selectedNudge.timestamp}</span>
                          </div>
                          <p className="text-neutral-200 mb-3">{selectedNudge.message}</p>

                          {/* Priority Badge */}
                          {selectedNudge.priority === 'high' && (
                            <div className="mb-3">
                              <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-red-100 text-red-800">
                                🔥 High Priority
                              </span>
                            </div>
                          )}

                          {/* Attachments */}
                          {selectedNudge.attachments && selectedNudge.attachments.length > 0 && (
                            <div className="space-y-2">
                              <h5 className="text-sm font-medium text-neutral-300">Attachments</h5>
                              {selectedNudge.attachments.map((attachment, index) => (
                                <div key={index} className="flex items-center space-x-2 p-2 bg-neutral-600 rounded">
                                  <Paperclip className="h-4 w-4 text-neutral-400" />
                                  <span className="text-sm text-neutral-300">{attachment.name}</span>
                                </div>
                              ))}
                            </div>
                          )}
                        </div>
                      </div>
                    </div>

                    {/* Reply History */}
                    {selectedNudge.replies && selectedNudge.replies.length > 0 && (
                      <div className="space-y-3">
                        <h5 className="text-sm font-medium text-neutral-300">Conversation</h5>
                        {selectedNudge.replies.map((reply, index) => (
                          <div key={index} className="bg-neutral-600 rounded-lg p-3">
                            <div className="flex items-start space-x-3">
                              <img
                                src={reply.sender.avatar}
                                alt={reply.sender.name}
                                className="w-8 h-8 rounded-full"
                              />
                              <div className="flex-1">
                                <div className="flex items-center space-x-2 mb-1">
                                  <h6 className="text-sm font-medium text-white">{reply.sender.name}</h6>
                                  <span className="text-xs text-neutral-400">{reply.timestamp}</span>
                                </div>
                                <p className="text-sm text-neutral-200">{reply.message}</p>
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                </div>

                {/* Action Buttons */}
                {selectedNudge.sender && (
                  <div className="border-t border-neutral-700 p-4">
                    <div className="flex space-x-2 mb-4">
                      <button
                        onClick={handleLike}
                        className="flex-1 bg-neutral-700 text-white py-2 px-4 rounded-lg hover:bg-neutral-600 transition-colors flex items-center justify-center space-x-2"
                      >
                        <Heart className="h-4 w-4" />
                        <span>Like</span>
                      </button>
                      <button
                        onClick={handleWontBeAble}
                        className="flex-1 bg-neutral-700 text-white py-2 px-4 rounded-lg hover:bg-neutral-600 transition-colors flex items-center justify-center space-x-2"
                      >
                        <Clock className="h-4 w-4" />
                        <span>Won't be able</span>
                      </button>
                    </div>

                    {/* Reply Input */}
                    <div className="flex space-x-2">
                      <input
                        type="text"
                        value={replyText}
                        onChange={(e) => setReplyText(e.target.value)}
                        placeholder="Type your reply..."
                        className="flex-1 bg-neutral-700 border border-neutral-600 rounded-lg px-3 py-2 text-white placeholder-neutral-400 focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent"
                        onKeyPress={(e) => e.key === 'Enter' && handleReply()}
                      />
                      <button
                        onClick={handleReply}
                        disabled={!replyText.trim()}
                        className="bg-white text-black px-4 py-2 rounded-lg hover:bg-gray-100 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                      >
                        <Send className="h-4 w-4" />
                      </button>
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </animated.div>
    </div>
  );
};

export default NudgeConversationPanel;
